input.content:
# Backup Huawei Phone Internal Storage
$ErrorActionPreference = "Continue"

$shell = New-Object -ComObject Shell.Application
$computer = $shell.NameSpace(17)

# Find the phone
$phone = $computer.Items() | Where-Object { $_.Name -like "*HUAWEI*" }
if (-not $phone) {
    Write-Host "Phone not found!" -ForegroundColor Red
    exit 1
}

Write-Host "Found: $($phone.Name)" -ForegroundColor Green

# Get internal storage
$internalStorage = $phone.GetFolder.Items() | Where-Object { $_.Name -like "*内部*" -or $_.Name -like "*Internal*" }
if (-not $internalStorage) {
    # If no specific internal storage folder, use phone's first folder
    $phoneFolder = $phone.GetFolder()
} else {
    $phoneFolder = $internalStorage.GetFolder()
}

Write-Host "Copying from: $($phoneFolder.Title)" -ForegroundColor Green
Write-Host "To: E:\MateX5_Backup_20260221" -ForegroundColor Green

$destination = "E:\MateX5_Backup_20260221"
if (-not (Test-Path $destination)) {
    New-Item -ItemType Directory -Path $destination -Force
}

# Get total size for progress
$totalFiles = 0
$totalSize = 0
$phoneFolder.Items() | ForEach-Object {
    $totalFiles++
    if ($_.Size) { $totalSize += $_.Size }
}

Write-Host "Total files: $totalFiles, Total size: $([math]::Round($totalSize/1GB, 2)) GB" -ForegroundColor Cyan

# Copy files with progress
$copiedFiles = 0
$copiedSize = 0
$startTime = Get-Date

foreach ($item in $phoneFolder.Items()) {
    $copiedFiles++
    $itemName = $item.Name

    if ($item.Size) { $copiedSize += $item.Size }

    $percent = [math]::Round(($copiedFiles / $totalFiles) * 100, 1)
    $speedGB = [math]::Round(($copiedSize / 1GB) / ((Get-Date) - $startTime).TotalSeconds, 2)

    Write-Host "[$copiedFiles/$totalFiles] $percent% - Copying: $itemName" -ForegroundColor Cyan

    try {
        if ($item.IsFolder) {
            $destPath = Join-Path $destination $itemName
            if (-not (Test-Path $destPath)) {
                New-Item -ItemType Directory -Path $destPath -Force | Out-Null
            }
            # Recursively copy folder contents
            $subFolder = $item.GetFolder()
            foreach ($subItem in $subFolder.Items()) {
                try {
                    $shell.NameSpace($destPath).CopyHere($subItem, 0x400)
                } catch {
                    Write-Host "  ERROR copying: $($subItem.Name)" -ForegroundColor Red
                }
            }
        } else {
            $shell.NameSpace($destination).CopyHere($item, 0x400)
        }
    } catch {
        Write-Host "  ERROR copying: $itemName" -ForegroundColor Red
    }
}

$elapsed = (Get-Date) - $startTime
Write-Host "`nBackup completed in $($elapsed.ToString('hh\:mm\:ss'))" -ForegroundColor Green
Write-Host "Destination: $destination" -ForegroundColor Green

