# Backup Huawei Phone Internal Storage - Direct Mode
$ErrorActionPreference = "Continue"
$ProgressPreference = "SilentlyContinue"

Add-Type -AssemblyName System.Windows.Forms

$shell = New-Object -ComObject Shell.Application
$computer = $shell.NameSpace(17)

# Find the phone
$phone = $computer.Items() | Where-Object { $_.Name -like "*HUAWEI*" }
if (-not $phone) {
    Write-Host "Phone not found!" -ForegroundColor Red
    exit 1
}

Write-Host "Found: $($phone.Name)" -ForegroundColor Green

# Get internal storage folder
$phoneFolder = $phone.GetFolder()
$internalStorage = $null

foreach ($item in $phoneFolder.Items()) {
    if ($item.Name -like "*内部*" -or $item.Name -like "*Internal*") {
        $internalStorage = $item
        break
    }
}

if ($internalStorage) {
    $sourceFolder = $internalStorage.GetFolder()
    Write-Host "Source: $($internalStorage.Name)" -ForegroundColor Green
} else {
    $sourceFolder = $phoneFolder
    Write-Host "Source: Phone Root" -ForegroundColor Green
}

$destination = "E:\MateX5_Backup_20260221"
if (-not (Test-Path $destination)) {
    New-Item -ItemType Directory -Path $destination -Force
}

Write-Host "Destination: $destination" -ForegroundColor Green
Write-Host "Starting backup..." -ForegroundColor Cyan

# Count files
$fileCount = 0
$folderCount = 0
function Count-Files($folder) {
    foreach ($item in $folder.Items()) {
        if ($item.IsFolder) {
            $folderCount++
            Count-Files $item.GetFolder()
        } else {
            $fileCount++
        }
    }
}

Write-Host "Counting files..." -ForegroundColor Yellow
Count-Files $sourceFolder
Write-Host "Found $fileCount files in $folderCount folders" -ForegroundColor Cyan

# Copy function
$copied = 0
$startTime = Get-Date

function Copy-FolderRecursive($source, $destPath) {
    $destFolder = $shell.NameSpace($destPath)

    foreach ($item in $source.Items()) {
        $script:copied++

        if ($item.IsFolder) {
            $newDest = Join-Path $destPath $item.Name
            if (-not (Test-Path $newDest)) {
                New-Item -ItemType Directory -Path $newDest -Force | Out-Null
            }
            Write-Host "[$script:copied/$fileCount] FOLDER: $($item.Name)"
            Copy-FolderRecursive $item.GetFolder() $newDest
        } else {
            $sizeMB = [math]::Round($item.Size / 1MB, 2)
            Write-Host "[$script:copied/$fileCount] FILE: $($item.Name) ($sizeMB MB)"
            $destFolder.CopyHere($item, 0x400)
        }
    }
}

Copy-FolderRecursive $sourceFolder $destination

$elapsed = (Get-Date) - $startTime
Write-Host "`n========================================" -ForegroundColor Green
Write-Host "Backup completed in $($elapsed.ToString('hh\:mm\:ss'))" -ForegroundColor Green
Write-Host "Destination: $destination" -ForegroundColor Green
Write-Host "========================================" -ForegroundColor Green

