# Recursive Backup of Internal Storage
$ErrorActionPreference = "Continue"
$ProgressPreference = "SilentlyContinue"

$shell = New-Object -ComObject Shell.Application

# Navigate to Internal Storage
$computer = $shell.NameSpace(17)
$phone = $computer.Items() | Where-Object { $_.Name -like "*HUAWEI*" }
$phoneFolder = $phone.GetFolder()

# Find Internal Storage
$internalStorage = $null
foreach ($item in $phoneFolder.Items()) {
    if ($item.Name -like "*内部*") {
        $internalStorage = $item
        break
    }
}

if (-not $internalStorage) {
    Write-Host "Internal Storage not found!" -ForegroundColor Red
    exit 1
}

$sourceFolder = $internalStorage.GetFolder()
$baseDest = "E:\MateX5_Backup_20260221"

Write-Host "Source: Internal Storage" -ForegroundColor Green
Write-Host "Destination: $baseDest" -ForegroundColor Green

$startTime = Get-Date
$totalCopied = 0

function Copy-Recursive($folder, $destPath) {
    # Ensure destination exists
    if (-not (Test-Path $destPath)) {
        New-Item -ItemType Directory -Path $destPath -Force | Out-Null
    }

    $destNS = $shell.NameSpace($destPath)
    $items = @($folder.Items())

    for ($i = 0; $i -lt $items.Count; $i++) {
        $item = $items[$i]
        $script:totalCopied++
        $elapsed = ((Get-Date) - $startTime).ToString('hh\:mm\:ss')

        if ($item.IsFolder) {
            $newDest = Join-Path $destPath $item.Name
            Write-Host "[$elapsed] [$script:totalCopied] FOLDER: $($item.Path)"
            try {
                Copy-Recursive $item.GetFolder() $newDest
            } catch {
                Write-Host "  ERROR: $_" -ForegroundColor Red
            }
        } else {
            $sizeStr = if ($item.Size) { "($([math]::Round($item.Size/1MB, 2)) MB)" } else { "" }
            Write-Host "[$elapsed] [$script:totalCopied] FILE: $($item.Name) $sizeStr"
            try {
                $destNS.CopyHere($item, 0x400)
            } catch {
                Write-Host "  ERROR: $_" -ForegroundColor Red
            }
        }
    }
}

# Clear existing 内部存储 and start fresh
$internalDest = Join-Path $baseDest "内部存储"
if (Test-Path $internalDest) {
    Remove-Item -Recurse -Force $internalDest
}
New-Item -ItemType Directory -Path $internalDest -Force | Out-Null

Write-Host "Starting recursive backup..." -ForegroundColor Cyan
Copy-Recursive $sourceFolder $internalDest

$elapsed = (Get-Date) - $startTime
Write-Host "`n========================================" -ForegroundColor Green
Write-Host "Completed in $($elapsed.ToString('hh\:mm\:ss'))" -ForegroundColor Green
Write-Host "Total items processed: $totalCopied" -ForegroundColor Green
Write-Host "========================================" -ForegroundColor Green

